INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$JSON-to-API form engine$q$, $q$Every form definition automatically generates a REST API, submission schema, and validation ruleset, so developers do not need to hand-build backend endpoints for each intake process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Self-hosted deployment$q$, $q$Ships as Docker containers deployed inside a customer's own infrastructure and attached to the customer's own databases, keeping sensitive submission data within the organization's security boundary.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$PDF Server and PDF Plus$q$, $q$Converts submitted form data into pixel-perfect, templated PDFs and can ingest existing PDF forms, turning them into dynamic, validated web forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Multi-tenant architecture$q$, $q$Supports isolated, white-labeled customer environments so SaaS platforms can offer form capabilities to their own end customers under one Form.io deployment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$E-Sign Plus digital signatures$q$, $q$Provides cryptographic signatures bound directly to submission data rather than to a static document, supporting compliance-grade audit requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Enterprise Form Builder module$q$, $q$Lets organizations embed a white-labeled, drag-and-drop form creation experience for their own end users inside their applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Reporting UI module$q$, $q$Adds interactive, embedded data analytics and dashboards built directly on top of submission data without exporting to a separate BI tool.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$AI and MCP integration$q$, $q$Includes an MCP server and a Claude Code plugin so AI agents can read and write governed form data through the same audited API layer as human-built integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Form-to-API generation eliminates significant custom backend development for structured data collection$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Self-hosted architecture keeps sensitive submission data inside the organization's own security and compliance boundary$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Strong fit for regulated industries needing audit trails, field-level logging, and form versioning$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$PDF generation and legacy PDF-to-web-form conversion is a differentiated capability versus most form builders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Long operating history since 2015 and an established enterprise and public-sector customer base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Configuration-based pricing across many separate components makes total cost difficult to estimate upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Self-hosted deployment model requires more DevOps effort than a purely hosted SaaS form tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Not designed for quick, no-code marketing landing-page forms compared to lightweight competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Publicly disclosed funding is modest, and detailed company size and revenue figures are not publicly documented$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Steeper learning curve for non-developers compared to consumer-facing form builders$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Is Form.io open source?$q$, $q$Form.io has an open-source core with additional commercial modules and enterprise licensing layered on top for features like advanced security, PDF generation, and reporting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Does Form.io offer a free plan?$q$, $q$Form.io offers a free SaaS trial with no credit card required, including one project, unlimited developers and form builders, and up to one million submissions per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Who is Form.io built for?$q$, $q$Form.io is built primarily for enterprise development teams in regulated industries such as insurance, healthcare, government, and financial services that need standardized, auditable data collection integrated with existing systems.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Can Form.io be self-hosted?$q$, $q$Yes, Form.io is typically deployed as Docker containers inside a customer's own infrastructure and connected to the customer's own databases, which is a core part of its enterprise value proposition.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Who founded Form.io?$q$, $q$Form.io was founded in 2015 in Dallas, Texas by CEO Gary Wetzel, CTO Travis Tidwell, and co-founder Denise Kay.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$How does Form.io differ from tools like JotForm or Typeform?$q$, $q$Unlike hosted, consumer-facing form builders, Form.io generates a full API, validation schema, and governed data workflow for every form, and is designed to be self-hosted and integrated into existing enterprise systems rather than used as a standalone hosted form page.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Regulated intake and compliance workflows$q$, $q$Insurance, healthcare, and government teams use Form.io to standardize intake forms with field-level audit logging, versioning, and PDF output required for compliance.$q$, $q$Enterprise IT and compliance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Embedding white-labeled form building in a SaaS product$q$, $q$Multi-tenant architecture and the Enterprise Form Builder module let SaaS platforms offer form creation to their own end customers under their own branding.$q$, $q$SaaS product and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Modernizing legacy paper and PDF forms$q$, $q$Organizations use the PDF Server to convert existing PDF forms into dynamic, validated web forms and generate pixel-perfect PDF output from new digital submissions.$q$, $q$Public-sector and enterprise operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$SaaS Free Trial$q$, $q$Free$q$, $q$No credit card required$q$, NULL, $q$["1 project","Unlimited developers and form builders","Up to 1,000,000 submissions per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$API Server Environment$q$, $q$$330/month$q$, $q$monthly$q$, NULL, $q$["Unlimited API calls and submissions","Supports production and non-production SDLC environments"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$API Plus Server Environment$q$, $q$$660/month$q$, $q$monthly$q$, NULL, $q$["All API Server capabilities","Audit logging","Encryption and compliance tooling"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Enterprise Level Project$q$, $q$$330/month$q$, $q$monthly$q$, NULL, $q$["Unlimited developers and form builders","Unlimited forms and resources","Minimum one required per application"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$PDF Server / PDF Plus$q$, $q$$330-$660/month$q$, $q$monthly$q$, NULL, $q$["Unlimited PDF submission downloads","PDF Plus adds pixel-perfect backgrounds and custom templates"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$Enterprise (custom modules)$q$, $q$Contact for pricing$q$, $q$custom$q$, NULL, $q$["Reporting UI Module","Multi-Tenanted Platform","Accessibility Compliance Module","Enterprise Form Builder Module","5-year developer licenses"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Form.io is a self-hosted, developer-oriented platform that converts JSON form definitions into working APIs, validation logic, PDFs, and governed submission workflows. It is built for enterprise and public-sector teams that need standardized, auditable data collection integrated with existing systems rather than a standalone hosted form page.$q$, $q$Founded in 2015 in Dallas, Texas by Gary Wetzel, Travis Tidwell, and Denise Kay, Form.io has grown through direct enterprise sales rather than large venture funding rounds, and remains privately held and self-hosted-first in its architecture.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every form built in Form.io automatically generates a REST API, a submission schema, and validation rules, eliminating the need to hand-build backend endpoints for each new intake process.$q$, $q$The platform includes a PDF Server for generating pixel-perfect templated PDFs from submissions and converting legacy PDF forms into dynamic web forms, plus an Enterprise Form Builder module, a Reporting UI for embedded analytics, an E-Sign Plus digital signature module, and an MCP server for AI agent integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Form.io uses configuration-based pricing built from priced components rather than flat per-seat tiers: an API Server Environment runs about $330 per month, API Plus about $660 per month, and an Enterprise Project (minimum one per application) about $330 per month, with parallel PDF Server tiers at the same price points.$q$, $q$Optional modules such as Reporting UI, Multi-Tenant support, Accessibility Compliance, and the Enterprise Form Builder are priced separately, typically $330 to $660 per month each, and a free SaaS trial with up to one million monthly submissions is available for evaluation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a141dc6c-48ce-4194-aa10-52dc5225f542', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Lifestyle Spending Accounts (LSA)$q$, $q$Configurable accounts covering wellness, family planning, professional development, home office, and other lifestyle categories that traditional benefits plans typically exclude.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Health Spending Accounts, HRA, and FSA support$q$, $q$In addition to LSAs, Forma administers Health Spending Accounts, Health Reimbursement Arrangements, and Flexible Spending Accounts on the same underlying platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Forma Visa Card$q$, $q$A physical and virtual card that lets employees spend allocated benefits funds directly at eligible merchants without submitting a manual reimbursement claim.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Forma Store$q$, $q$A curated marketplace of discounted products and services that employees can purchase directly using their benefits account balance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Reimbursement claims and member support$q$, $q$A traditional claims submission workflow backed by Forma's in-house member support team for purchases made outside the card network or marketplace.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$HR admin configuration dashboard$q$, $q$Lets People teams define eligible categories, funding amounts, and program rules across multiple benefit types from a single web-based dashboard.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Employee mobile app$q$, $q$Lets employees check balances, browse the Forma Store, and submit reimbursement claims directly from a phone.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Benefits program analytics and reporting$q$, $q$Gives HR teams visibility into program utilization and spend, supporting benchmarking and funding-strategy decisions to drive engagement.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Highly configurable benefit categories go well beyond fixed wellness-only stipend tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Three funding mechanisms (card, marketplace, and reimbursement) reduce friction for employees compared to reimbursement-only competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Backed by well-known fintech and HR-tech investors, signaling financial stability for a benefits vendor employees depend on$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Strong enterprise customer base including well-known technology companies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Single platform can consolidate multiple point-solution benefit vendors into one system$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Pricing is not publicly available and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Designed for mid-market and enterprise HR teams, not well suited to very small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$As with any flexible-spending-account vendor, employee benefit is limited to the funding amount the employer chooses to allocate$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Detailed public documentation of technical architecture and API access is limited compared to developer-focused platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$What was Forma called before it was Forma?$q$, $q$Forma was originally launched as Twic in 2017 and rebranded to Forma in March 2022 alongside a $40 million Series B funding round.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$How much funding has Forma raised?$q$, $q$Forma has raised approximately $57.6 million in total funding across five rounds, including a $40 million Series B round in 2022, from investors such as Emergence Capital, Ribbit Capital, and Stripe.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Who founded Forma?$q$, $q$Forma was founded in 2017 by CEO Jason Fan and CTO Max Hsieh.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$How do employees spend their Forma benefits funds?$q$, $q$Employees can spend through the Forma Store marketplace, the Forma Visa Card at eligible merchants, or submit a reimbursement claim for eligible purchases made elsewhere.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Is Forma pricing publicly listed?$q$, $q$No, Forma is sold as an enterprise B2B platform and pricing is provided by contacting the company's sales team based on headcount and program design.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$What types of benefit accounts does Forma support?$q$, $q$Forma supports Lifestyle Spending Accounts, Health Spending Accounts, Health Reimbursement Arrangements, and Flexible Spending Accounts on one platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Consolidating fragmented wellness and lifestyle benefits$q$, $q$HR teams replace multiple point-solution vendors for wellness, home office, and professional development stipends with one configurable Forma program.$q$, $q$HR and People teams at mid-market to enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Administering compliant HSA, FSA, and HRA programs$q$, $q$Benefits and finance teams use Forma to manage tax-advantaged health accounts alongside lifestyle spending accounts on the same platform.$q$, $q$Benefits administrators and finance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Improving benefits engagement for distributed workforces$q$, $q$Companies with remote or global teams use the Forma Visa Card and mobile app to make benefits usable regardless of employee location.$q$, $q$People operations teams at distributed or global companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$Custom Enterprise Plan$q$, $q$Contact for pricing$q$, $q$custom$q$, NULL, $q$["Configurable Lifestyle Spending Account programs","HSA, FSA, and HRA administration","Forma Visa Card issuance","Forma Store marketplace access","Dedicated member support for reimbursement claims","HR admin dashboard and reporting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Forma is a flexible employee benefits platform that lets HR teams design custom Lifestyle Spending Accounts, Health Spending Accounts, HRAs, and FSAs on one system, replacing point-solution vendors with a single configurable administrative layer.$q$, $q$Founded in 2017 by Jason Fan and Max Hsieh as Twic, the company rebranded to Forma in March 2022 alongside a $40 million Series B round, broadening its scope from wellness stipends to the full range of flexible workplace benefits.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Employees access allocated funds through the Forma Store marketplace, a Forma Visa Card for direct spending, or a traditional reimbursement claims process backed by dedicated member support, giving HR teams multiple funding mechanisms in one platform.$q$, $q$HR administrators can configure eligible expense categories, funding rules, and reimbursement policies per program, supporting highly custom benefits design rather than a fixed menu of predefined benefit types.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Forma does not publish self-serve pricing; as an enterprise B2B HR platform, pricing depends on employee headcount and program complexity and is quoted through direct sales.$q$, $q$The company is backed by roughly $57.6 million in total funding across five rounds, including a $40 million Series B in 2022, from investors such as Emergence Capital, Ribbit Capital, and Stripe.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('558c959c-6ffc-4bcf-b6cc-8dce9830952a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$AI-assisted compensation plan design$q$, $q$Applies machine learning to model and simulate proposed sales compensation plan changes before they are rolled out to the sales organization.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Territory planning$q$, $q$Helps RevOps teams design and adjust sales territories based on account potential, capacity, and historical performance data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Quota management$q$, $q$Supports setting, tracking, and adjusting sales quotas in alignment with compensation plan design and revenue targets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Unified sales performance data foundation$q$, $q$Ingests CRM, payroll, and performance data into a queryable data layer used across compensation, territory, and quota decisions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$What-if scenario modeling$q$, $q$Lets sales finance and compensation teams simulate the financial and behavioral impact of plan changes before implementation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Compensation plan monitoring and alerts$q$, $q$Continuously tracks whether live compensation plans remain aligned with revenue goals as market and go-to-market conditions change.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Integrations with CRM and payroll systems$q$, $q$Connects to systems of record such as CRM and HRIS/payroll platforms to keep compensation, territory, and quota data synchronized.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Enterprise-grade reporting and analytics$q$, $q$Provides sales leadership with visibility into how compensation design decisions are playing out across a large, complex sales organization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Focuses on strategic compensation plan design and simulation, not just payout calculation, differentiating it from calculation-centric ICM tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Well capitalized with roughly $58 million in funding, supporting continued product investment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Strong reference customers with large, complex sales organizations such as Autodesk and Stryker$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Purpose-built for territory, quota, and compensation planning together rather than as separate point tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Pricing is not public and requires an enterprise sales process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Best suited to large, complex sales organizations, likely overkill for small sales teams with simple compensation structures$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Implementation typically requires integration with existing CRM and payroll systems, adding setup time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Detailed technical architecture and API documentation are not broadly publicly available$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$What does Forma.ai do?$q$, $q$Forma.ai is an AI-powered sales performance management platform that helps enterprises design, simulate, and optimize sales compensation plans, territory assignments, and sales quotas.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Who founded Forma.ai and when?$q$, $q$Forma.ai was founded in 2016 by CEO Nabeil Alazzam and is headquartered in Toronto, Ontario, Canada.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$How much funding has Forma.ai raised?$q$, $q$Forma.ai has raised approximately $58 million across three rounds: a $3 million seed round, a $10 million Series A, and a $45 million Series B.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Who are Forma.ai's customers?$q$, $q$Publicly referenced Forma.ai customers include Autodesk, CareerBuilder, Stryker, Trustpilot, and OpenTable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$How is Forma.ai different from traditional incentive compensation management tools?$q$, $q$Forma.ai emphasizes AI-assisted compensation plan design and what-if simulation before rollout, rather than focusing primarily on calculating and paying out commissions after a plan is already set.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Is Forma.ai pricing publicly available?$q$, $q$No, Forma.ai is sold as an enterprise B2B platform and pricing is provided through the sales team based on sales team size and modules licensed.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Designing and simulating compensation plan changes$q$, $q$Sales finance and RevOps teams model the projected cost and behavioral impact of a proposed compensation plan before rolling it out company-wide.$q$, $q$Sales operations and sales finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Optimizing sales territories and quotas$q$, $q$Revenue leaders use Forma.ai to design territory assignments and set quotas that better reflect account potential and rep capacity.$q$, $q$Chief Revenue Officers and VPs of Sales Operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Monitoring compensation plan alignment over time$q$, $q$Enterprises use Forma.ai to continuously track whether existing compensation structures remain aligned with revenue goals as the business evolves.$q$, $q$Enterprise sales leadership and compensation analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$Custom Enterprise Plan$q$, $q$Contact for pricing$q$, $q$custom$q$, NULL, $q$["AI-assisted compensation plan design and simulation","Territory planning module","Quota management module","CRM and payroll system integrations","Enterprise reporting and analytics","Dedicated implementation support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Forma.ai is an AI-powered sales performance management platform that helps large enterprises design, simulate, and optimize sales compensation plans, territory assignments, and quotas from a single data foundation.$q$, $q$Founded in 2016 by CEO Nabeil Alazzam in Toronto, Canada, the company has raised roughly $58 million across three rounds, growing on the back of reported triple-digit year-over-year revenue growth.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform focuses on compensation plan design and what-if simulation, letting RevOps and sales finance teams model the financial and behavioral impact of a proposed plan change before rolling it out.$q$, $q$Forma.ai also covers territory planning and quota management, integrating CRM and sales performance data into a live data foundation used to continuously monitor whether existing compensation plans remain aligned with revenue goals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Forma.ai does not publish self-serve pricing; as an enterprise SPM platform, pricing is quoted directly by the sales team and generally scales with the number of sales representatives covered and modules licensed.$q$, $q$Deployments typically involve integration work with a customer's CRM, HRIS, and payroll systems rather than a simple self-serve signup, consistent with other enterprise incentive compensation platforms.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d52f8727-8700-449a-a039-f5c8df0a1fe0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Photography-focused portfolio themes$q$, $q$More than 90 professionally designed templates with thousands of customizable design variables built specifically around image-heavy portfolios.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Client proofing galleries$q$, $q$Dedicated galleries for sharing work-in-progress images with clients for selection and approval, included on every plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Commission-free online store$q$, $q$Built-in e-commerce for selling prints and digital downloads without Format taking a percentage cut of sales.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Adobe Lightroom integration$q$, $q$Publishes images directly from Lightroom to a Format portfolio without leaving the existing editing workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Custom code editor$q$, $q$Available on Pro and Pro Plus tiers, letting advanced users customize beyond the built-in template design system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Mobile app for site management$q$, $q$A companion mobile app lets photographers manage their site and view analytics on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$SEO tools and SSL security$q$, $q$Includes basic SEO tooling, SSL security, and copyright protection on every plan to help portfolio sites rank and stay secure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Hosted video and high-storage tiers$q$, $q$Higher-tier plans include dedicated hosted video minutes and up to 1TB of storage for image-heavy portfolios.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Commission-free store means photographers keep 100 percent of print and product sale revenue on paid plans$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Deep photography-specific workflow integration via Adobe Lightroom sync$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Client proofing galleries are built into every plan rather than sold as an add-on$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$More than a decade of operating history and a large template library aimed specifically at visual portfolios$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Annual billing offers a substantial discount versus month-to-month pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Higher standard monthly pricing than some general-purpose website builders if not committing to an annual plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Feature set is narrowly focused on photography and visual portfolios, less suited to non-visual small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Lower-tier Basic plan has meaningful limits on page count, images, and client galleries$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Now owned by Zenfolio, which could eventually affect long-term product direction or brand independence$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Who owns Format?$q$, $q$Format is owned by Zenfolio, a competing photography website and print-sales platform, though Format continues to operate as its own branded product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$How much does Format cost?$q$, $q$Format's Basic plan starts at $14/month ($10/month billed annually), with Pro at $24/month ($12/month annually) and Pro Plus at $36/month ($15/month annually).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Does Format take a commission on print sales?$q$, $q$No, Format's built-in online store is commission-free on all paid plans, meaning Format does not take a percentage cut of print or product sales.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Is there a free trial for Format?$q$, $q$Yes, Format offers a 14-day free trial with no credit card required.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Does Format integrate with Adobe Lightroom?$q$, $q$Yes, Format integrates directly with Adobe Lightroom, letting photographers publish images to their portfolio from within their existing editing workflow.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Who is Format best suited for?$q$, $q$Format is best suited for photographers, artists, and other visual creative professionals who need an image-first portfolio site with client proofing and print sales, rather than a general small-business website.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Building a professional photography portfolio$q$, $q$Photographers use Format's templates and Lightroom integration to publish a polished, image-heavy portfolio site quickly.$q$, $q$Professional and semi-professional photographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Client proofing and print sales$q$, $q$Photographers share proofing galleries with clients for selection, then sell prints and digital downloads through Format's commission-free store.$q$, $q$Wedding, portrait, and event photographers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Showcasing visual creative work beyond photography$q$, $q$Designers and illustrators use Format's portfolio themes to present visual work with a similarly image-focused layout.$q$, $q$Designers and illustrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Basic$q$, $q$$14/month ($10/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["10 website pages","70 high-resolution images","Mobile optimization","Lightroom integration","SSL security","3 client galleries","2GB file transfers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Pro$q$, $q$$24/month ($12/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited pages","1,500 high-resolution images","100GB storage","15 hosted video minutes","Commission-free store (15 products)","Custom code editor","50 client galleries","5GB file transfers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$Pro Plus$q$, $q$$36/month ($15/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited pages and images","1TB storage","120 hosted video minutes","Commission-free store (1,000 products)","Priority support","Photography Business Masterclass course","250 client galleries","10GB file transfers"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Format is a website builder purpose-built for photographers and visual creatives, offering portfolio templates, client proofing galleries, and commission-free e-commerce rather than the general-purpose feature set of a horizontal website builder.$q$, $q$Founded in 2010 in Toronto, Canada, Format is now owned by Zenfolio, a close competitor in the photography website space, though it continues to operate as a distinct branded product with its own pricing and templates.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every plan includes integrated e-commerce, blogging, and client proofing galleries, along with more than 90 customizable themes, Adobe Lightroom integration, and a mobile app for managing a site on the go.$q$, $q$The built-in online store is commission-free across all paid tiers, meaning Format does not take a cut of print or product sales, a meaningful differentiator for photographers relying on print revenue.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Format offers three tiers: Basic at $14/month ($10/month annually), Pro at $24/month ($12/month annually), and Pro Plus at $36/month ($15/month annually), each stepping up storage, image counts, video minutes, and store product limits.$q$, $q$A 14-day free trial requiring no credit card is available across plans, and Format periodically runs promotions of up to 50 percent off annual subscriptions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('036ebb4f-fc22-4057-831e-b9e581009137', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Open-source, self-hostable core$q$, $q$The full survey application is licensed under AGPLv3 and can be self-hosted via Docker for complete data ownership and control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$In-product, website, and link surveys$q$, $q$Supports three distinct survey delivery modes so teams can gather feedback inside an app, on a public website, or via a shareable link.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Segment-based targeting$q$, $q$Lets product teams target specific in-app surveys to user segments based on behavioral or account attributes rather than showing the same survey to everyone.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Native iOS and Android SDKs$q$, $q$Enables triggering and displaying surveys directly inside mobile apps for in-product feedback collection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$GDPR-compliant EU-hosted cloud$q$, $q$Offers a managed cloud option hosted in Frankfurt, Germany, for teams that want compliance guarantees without self-hosting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$AI-assisted translation and response labeling$q$, $q$Automatically translates surveys across languages and applies AI topic and subtopic labeling to open-text responses on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Quota management$q$, $q$Controls how many responses a given segment or channel can contribute, available on the Scale plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Custom webhooks and full API access$q$, $q$Pushes response data into other systems in real time and allows fully programmatic survey management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Fully open-source AGPLv3 core with genuine self-hosting option, not just a marketing claim$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Generous free Hobby tier with 250 monthly responses and the same core feature set as paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$GDPR-native, EU-hosted cloud option appeals directly to privacy-conscious and European organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Native mobile SDKs and segment targeting support serious in-product research use cases, not just basic forms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Backed by OSS Capital, a fund specialized in open-source business models, reinforcing long-term open-source commitment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Free tier response limit (250/month) is modest for teams running frequent in-product surveys$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Self-hosting requires DevOps effort to run and maintain via Docker$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Jump from Pro ($74/month) to Scale ($325/month) is steep for teams needing quota management or advanced AI labeling$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Smaller company and community scale than incumbents like Qualtrics, which may mean fewer integrations or slower feature parity$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Is Formbricks really open source?$q$, $q$Yes, Formbricks' core application is licensed under AGPLv3 and can be self-hosted for free for personal and commercial use, including link, website, and in-app surveys.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Who founded Formbricks?$q$, $q$Formbricks was founded in 2022 in Kiel, Germany by CEO Johannes Dancker and CTO Matti Nannt, evolving from an earlier project called snoopForms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Does Formbricks offer a free plan?$q$, $q$Yes, the Hobby plan is free and includes 1 workspace and up to 250 survey responses per month with the core feature set included.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Can Formbricks be self-hosted for GDPR compliance?$q$, $q$Yes, Formbricks can be fully self-hosted, and its managed cloud option is also GDPR-compliant and hosted in Frankfurt, Germany, for teams that prefer not to self-host.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$How much does Formbricks cost?$q$, $q$Formbricks' Pro plan costs $74/month for 2,000 monthly responses and unlimited team seats, while the Scale plan costs $325/month for 5,000 monthly responses and advanced features like quota management.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$How is Formbricks different from Typeform or Qualtrics?$q$, $q$Formbricks differentiates on open-source licensing and self-hosting options, positioning itself as a privacy-first alternative to hosted, closed-source platforms like Typeform and enterprise-only tools like Qualtrics.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$In-product research and feedback collection$q$, $q$Product teams use native mobile SDKs and segment targeting to trigger surveys based on specific user behavior inside an app.$q$, $q$Product managers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$GDPR-compliant customer feedback for European companies$q$, $q$European or privacy-sensitive organizations use the EU-hosted cloud or self-hosted deployment to keep survey response data within regulatory boundaries.$q$, $q$European companies and compliance-driven organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Replacing a closed-source survey vendor$q$, $q$Teams migrate off Qualtrics or Typeform to Formbricks' open-source platform to reduce licensing costs and gain full data ownership.$q$, $q$Developer teams and data-privacy-focused organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Hobby$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["1 workspace","250 responses/month","Link, website, and in-app surveys","Conditional logic and hidden fields","Full API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Pro$q$, $q$$74/month$q$, $q$monthly (annual billing available with 2 months free)$q$, NULL, $q$["3 workspaces","2,000 responses/month","Unlimited team seats","Remove Formbricks branding","Respondent identification and segmentation","iOS and Android SDKs","AI translations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$Scale$q$, $q$$325/month$q$, $q$monthly (annual billing available with 2 months free)$q$, NULL, $q$["5 workspaces","5,000 responses/month","Teams and access roles","Quota management","AI topic and subtopic labeling","Custom dashboards","Two-factor authentication","reCAPTCHA spam protection"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formbricks is an open-source experience management platform for in-product, website, and link surveys, built as a privacy-first, self-hostable alternative to Qualtrics and Typeform.$q$, $q$Founded in 2022 in Kiel, Germany by CEO Johannes Dancker and CTO Matti Nannt, the company evolved from an earlier project called snoopForms and is backed by OSS Capital, a fund focused specifically on open-source software companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core application is licensed under AGPLv3 and can be self-hosted via Docker for full data control, or accessed through a GDPR-compliant, Frankfurt-hosted managed cloud for teams that prefer not to run their own infrastructure.$q$, $q$Beyond core survey building, Formbricks supports respondent identification, segment-based targeting, native iOS and Android SDKs, custom webhooks, a full API, and AI-assisted translation and response labeling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Formbricks offers a free Hobby plan with 250 monthly responses, a Pro plan at $74/month with 2,000 responses and branding removal, and a Scale plan at $325/month with 5,000 responses, quota management, and AI-based response labeling.$q$, $q$Annual billing includes a two-month-free discount, and reported figures put Formbricks at roughly $550,000 in annual recurring revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6b896e4-5bf3-4a3c-9f83-469792152818', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Hosted form backend endpoint$q$, $q$Lets any plain HTML form submit directly to Formcarry's endpoint without requiring the form owner to build or host server-side processing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Spam filtering$q$, $q$Applies automated spam detection to incoming submissions, with a claimed accuracy rate of 98.6 percent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$File upload handling$q$, $q$Accepts file uploads directly through the same form endpoint used for standard field data, without a separate upload service.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$AJAX submission support$q$, $q$Supports asynchronous form submission without a full page reload, available on every pricing tier including the free plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$3,000+ app integrations$q$, $q$Connects form submissions to third-party tools including Google Sheets, Mailchimp, Airtable, Discord, Slack, Notion, and Twilio through Zapier-style connectivity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Team collaboration and access roles$q$, $q$Supports inviting multiple team members to a workspace with different access levels starting from entry-level paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Custom email server and white-labeling$q$, $q$Lets teams send notification emails from their own custom email server and remove Formcarry branding, available even on the free tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$GDPR and CCPA compliance$q$, $q$The platform states compliance with GDPR and CCPA data-protection regulations for processing end-user-submitted personal data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Fast setup, typically a few minutes to connect an HTML form's action attribute to a working backend$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Generous free plan includes file uploads, custom email server, and white-labeling, not just basic email forwarding$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Broad integration ecosystem of over 3,000 apps via Zapier-style connectivity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Well suited to static-site hosting platforms like Netlify, Vercel, and GitHub Pages that have no native backend for form processing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Entry-level paid tier at $5/month undercuts many competitors for small projects$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Public information about founders, founding year, headquarters, and funding history is limited$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Submission limits scale quickly with usage, requiring plan upgrades for higher-traffic sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Customer logos cited in marketing (NBA, Continental, Yeezy, Cannes Film Festival) are not independently verified as full enterprise deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Less established public track record and documentation compared to category incumbents like Formspree$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$What does Formcarry do?$q$, $q$Formcarry is a form backend API that lets developers connect a plain HTML form to a hosted endpoint for email notifications, spam filtering, file uploads, and integrations without writing server-side code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Does Formcarry have a free plan?$q$, $q$Yes, the free Baby plan supports 50 submissions per month on one form with file upload support, a custom email server option, and white-labeling.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$How much does Formcarry cost?$q$, $q$Paid plans start at $5/month for the Starter tier (500 submissions/month, billed annually) and scale up to $80/month for the Premium tier (30,000 submissions/month), with custom Enterprise pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Does Formcarry work with static site builders like Webflow or Netlify?$q$, $q$Yes, Formcarry is designed for exactly this use case, letting forms on static or JAMstack sites without a traditional backend submit directly to a hosted endpoint.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Is Formcarry GDPR compliant?$q$, $q$Formcarry states that its platform is compliant with GDPR and CCPA data-protection regulations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Who founded Formcarry?$q$, $q$Formcarry's specific founders, founding year, and headquarters are not publicly documented in detail; it appears to operate as a smaller, likely bootstrapped SaaS product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Adding a working contact form to a static site$q$, $q$Developers point a plain HTML form's action attribute at a Formcarry endpoint to receive email notifications without building backend infrastructure.$q$, $q$Front-end developers and web designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Managing forms across many client sites$q$, $q$Agencies use Formcarry's team roles and multi-form support to manage contact and lead forms across multiple client websites from one dashboard.$q$, $q$Web design and development agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Routing form submissions into existing marketing tools$q$, $q$Small businesses connect Formcarry to Mailchimp, Google Sheets, or Slack via integrations to automatically route new leads into their existing workflow.$q$, $q$Small and medium businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Baby$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["50 submissions/month","1 form","1 team member","File upload support","Custom email server","White-label"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Starter$q$, $q$$5/month$q$, $q$billed annually$q$, NULL, $q$["500 submissions/month","Unlimited forms","3 team members","1GB file uploads","500 integration calls/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Basic$q$, $q$$15/month$q$, $q$billed annually$q$, NULL, $q$["2,000 submissions/month","Unlimited forms","5 team members","2GB file uploads","2,000 integration calls/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Premium$q$, $q$$80/month$q$, $q$billed annually$q$, NULL, $q$["30,000 submissions/month","Unlimited forms","20 team members","30GB file uploads","10,000 integration calls/month"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$custom$q$, NULL, $q$["99.9% uptime SLA","Unlimited submissions","Unlimited file uploads","Advanced support","Migration assistance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formcarry is a form backend API that lets developers connect a plain HTML form on a static site to a hosted endpoint, handling email notifications, spam filtering, file uploads, and third-party integrations without any server code.$q$, $q$It competes directly with Formspree, Getform, Basin, and Formcake in the form-backend category; public information on its founding team, founding year, and funding is limited, consistent with a smaller, likely bootstrapped SaaS product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Formcarry advertises a 98.6 percent spam-filtering accuracy rate, AJAX-based submission support on all tiers, and direct file upload handling through the same form endpoint used for standard fields.$q$, $q$The platform connects to over 3,000 apps through Zapier-style integrations, including Google Sheets, Mailchimp, Airtable, Discord, Slack, Notion, and Twilio, and states GDPR and CCPA compliance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Formcarry offers a free Baby plan with 50 monthly submissions, then Starter at $5/month, Basic at $15/month, and Premium at $80/month (all billed annually), scaling submission limits, team members, and file upload capacity.$q$, $q$An Enterprise plan with custom pricing adds a 99.9 percent uptime SLA, unlimited submissions and file uploads, and migration assistance for teams moving from another form backend provider.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('76d62d00-398c-4138-b919-379a5ca37c2b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Open-source, self-hostable core$q$, $q$The full FormPress application source code is available on GitHub and GitLab, allowing users to self-host on their own cloud infrastructure for complete data control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Drag-and-drop WYSIWYG editor$q$, $q$Lets users visually build forms by picking, arranging, and previewing elements exactly as end users will see them, without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Smart conditional logic$q$, $q$Dynamically shows or hides form fields and sections based on a respondent's previous answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$WordPress Gutenberg block integration$q$, $q$Embeds FormPress forms natively inside WordPress posts and pages through a custom Gutenberg block.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Zapier integration$q$, $q$Connects FormPress form submissions to more than 2,000 third-party applications without custom integration code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Google Sheets and Google Drive sync$q$, $q$Automatically pipes submitted form data into a connected Google Sheet or Drive folder.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Slack and Discord notifications$q$, $q$Sends real-time form submission alerts directly into a team's existing Slack or Discord workspace.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Custom webhooks$q$, $q$Allows arbitrary downstream automation by pushing form submission data to any webhook-compatible endpoint.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Genuinely open-source, with full application source code available for self-hosting, not just a limited community edition$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Free-to-use positioning lowers the barrier to entry for small businesses and individual developers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Native WordPress Gutenberg block integration is a strong fit for the large WordPress site-owner audience$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Broad integration coverage via Zapier, Slack, Discord, and Google Sheets despite being a small team$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Detailed public pricing tiers and paid plan specifics are not clearly documented, making cost planning harder for growing usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Small team size relative to larger form-builder competitors may mean slower feature development and support response$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Exact founding year and founder identities are not consistently documented in public sources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Less third-party review coverage and enterprise reference material compared to established competitors like JotForm or Typeform$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Is FormPress open source?$q$, $q$Yes, FormPress is an open-source form builder with source code available on GitHub and GitLab, and it can be self-hosted on a user's own cloud infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Where is FormPress based?$q$, $q$FormPress describes its company center as being in Ankara, Turkey, where the company states it was founded.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Is FormPress free to use?$q$, $q$FormPress positions itself as free to use, consistent with its open-source, self-host-oriented model, though detailed paid plan tiers are not clearly documented in public sources.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Does FormPress integrate with WordPress?$q$, $q$Yes, FormPress offers a dedicated Gutenberg block that lets WordPress users embed FormPress forms directly into posts and pages using the native block editor.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$What integrations does FormPress support?$q$, $q$FormPress integrates with Google Drive, Google Sheets, Slack, Discord, custom webhooks, and Zapier, which extends connectivity to more than 2,000 additional applications.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Who is FormPress best suited for?$q$, $q$FormPress is best suited for developers, small businesses, and WordPress site owners who want an open-source, self-hostable form builder rather than a closed-source SaaS platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Self-hosted data collection for privacy-sensitive teams$q$, $q$Organizations with strict data residency requirements self-host FormPress on their own infrastructure to keep form submission data fully under their control.$q$, $q$Privacy-conscious organizations and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Embedding forms natively in WordPress$q$, $q$WordPress site owners use the FormPress Gutenberg block to add forms directly inside posts and pages without a separate plugin interface.$q$, $q$WordPress site owners and publishers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Routing form submissions into existing team tools$q$, $q$Small businesses connect FormPress to Google Sheets, Slack, or Discord to automatically route new form submissions into their existing workflow.$q$, $q$Small businesses and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Drag-and-drop WYSIWYG form builder","Smart conditional logic","Self-hosting via open-source source code","Zapier, Slack, Discord, and Google Sheets integrations","WordPress Gutenberg block"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FormPress is an open-source, self-hostable form builder with a drag-and-drop WYSIWYG editor, letting users design custom data-collection forms and, if desired, run the entire application on their own infrastructure.$q$, $q$The company describes its center of operations as Ankara, Turkey, and third-party business data sources indicate a small team; an exact founding year is not consistently confirmed across public sources.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FormPress supports smart conditional logic for dynamically showing or hiding form sections based on prior answers, along with a strong focus on fast page-load performance for the forms it generates.$q$, $q$Integrations include Google Drive and Google Sheets, Slack, Discord, custom webhooks, Zapier for over 2,000 additional apps, and a dedicated WordPress Gutenberg block for embedding forms natively in the WordPress editor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FormPress positions itself as free to use, consistent with an open-source, self-host-first business model; detailed named paid tiers and specific price points were not found in publicly available sources at the time of this research.$q$, $q$Buyers with higher-volume or business-critical needs should confirm current commercial plan details directly with FormPress rather than assuming limits based on other form-builder pricing conventions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0118430-d952-414d-b1c2-ca4afbeb6470', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Advanced conditional branching logic$q$, $q$Tailors which questions a respondent sees next based on their previous answers, turning a form into a dynamic decision tree rather than a static questionnaire.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Real-time calculations$q$, $q$Computes values such as eligibility scores or estimated costs within a flow as the user progresses, and can display or act on that value before completion.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Complete design control$q$, $q$Pro and Enterprise tiers support custom CSS and custom domains for matching a flow's design precisely to an existing brand and product experience.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$HIPAA-compliant Enterprise tier$q$, $q$Offers HIPAA compliance, multiple environments, and an option to store submission data entirely outside Formsort's systems for regulated healthcare use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Split testing$q$, $q$Lets teams test different variants of a multi-step flow against each other to optimize conversion and completion rates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Native Stripe payment collection$q$, $q$Collects payments directly within a multi-step flow without requiring a separate checkout integration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Salesforce integration$q$, $q$Pushes qualified leads or completed applications directly into Salesforce for sales or clinical operations follow-up.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Form and funnel drop-off analytics$q$, $q$Provides detailed analytics on where users drop off within a multi-step flow, helping teams identify and reduce friction.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Purpose-built for complex, multi-step branching flows rather than simple single-page forms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$HIPAA compliance at the Enterprise tier makes it a strong fit for regulated healthcare and clinical use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Real-time calculations and native Stripe and Salesforce integrations support revenue- and eligibility-critical flows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Low-code interface lets product and clinical operations teams iterate on flows without full engineering builds$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Capital-efficient growth on modest funding suggests a stable, sustainably run company$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Pricing is based on flow starts rather than completions, which can be a less intuitive metric to budget against$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Pro plan at roughly $279/month is a meaningful jump from the 100-flow-start free tier for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Enterprise pricing (including HIPAA compliance) is not publicly listed and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Small team size (reportedly around nine people) relative to broader form-builder competitors may limit support bandwidth$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$What is Formsort used for?$q$, $q$Formsort is used to build complex, multi-step web forms and funnels with conditional branching logic, commonly for healthcare intake, insurance eligibility screening, and clinical trial or telehealth patient qualification flows.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Who founded Formsort?$q$, $q$Formsort was founded in 2019 and is headquartered in New York City, with reported co-founders Benjamin Fine and Fil Zembowicz.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Is Formsort HIPAA compliant?$q$, $q$HIPAA compliance is available on Formsort's Enterprise plan, along with multiple environments and the option to store submission data outside Formsort's own systems.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$How does Formsort pricing work?$q$, $q$Formsort prices based on flow starts per month: Free includes up to 100 flow starts, Pro costs about $279/month for 1,000 flow starts, and Enterprise is custom-priced for higher volume with additional compliance features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Does Formsort support payments?$q$, $q$Yes, Formsort supports native Stripe payment collection directly within a multi-step flow, without a separate checkout integration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$How is Formsort different from Typeform?$q$, $q$Formsort focuses specifically on complex, branching, multi-step flows with real-time calculations and regulated-industry compliance like HIPAA, while Typeform is more general-purpose and oriented toward simpler single-flow forms and surveys.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Clinical trial and telehealth patient screening$q$, $q$Healthcare and telehealth companies use branching logic to screen patients for eligibility for specific treatments, care pathways, or clinical trials.$q$, $q$Healthcare and telehealth product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Insurance and financial eligibility qualification$q$, $q$Insurtech and fintech companies build multi-step qualification flows with real-time calculations to determine applicant eligibility and pricing.$q$, $q$Insurtech and fintech product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$High-conversion, multi-step lead qualification funnels$q$, $q$Growth teams use split testing and drop-off analytics to optimize long, branching lead-qualification funnels for conversion.$q$, $q$Growth and marketing operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 100 flow starts/month","Unlimited users and forms","Custom logo and colors","Formsort branding included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Pro$q$, $q$$279/month (~$233/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1,000 flow starts/month","Complete design control","Custom CSS and custom domain","Split testing","Stripe payments","Salesforce integration","Form analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$custom$q$, NULL, $q$["More than 1,000 flow starts/month","HIPAA compliance","Multiple environments","Advanced roles and permissions","External-only data storage option","Dedicated implementation manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formsort is a low-code platform for building complex, multi-step web forms and funnels with conditional branching logic, real-time calculations, and complete design control, widely used for healthcare intake, eligibility screening, and clinical trial qualification flows.$q$, $q$Founded in 2019 and headquartered in New York City by co-founders Benjamin Fine and Fil Zembowicz, Formsort has raised roughly $4 million from investors including Notation Capital, BoxGroup, and Quint Capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Advanced branching logic tailors which questions a respondent sees based on prior answers, while real-time calculations let a flow compute eligibility scores or estimated costs as the user progresses.$q$, $q$Paid tiers add complete design control with custom CSS and custom domains, split testing, native Stripe payment collection, Salesforce integration, and detailed drop-off analytics across multi-step flows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Formsort prices by flow starts rather than form views: Free covers up to 100 flow starts/month, Pro costs about $279/month (or ~$233/month billed annually) for 1,000 flow starts, and Enterprise is custom-priced for higher volume.$q$, $q$The Enterprise tier adds HIPAA compliance, multiple environments, advanced roles and permissions, and an option to store data entirely outside Formsort's systems, reflecting its strength in regulated healthcare and fintech use cases.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
