INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2118c9da-01b6-493f-b26d-224cc4de5ba8', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
